#!/usr/local/bin/python3.13"""    procvw is a process viewer developed for FreeBSD.    Copyright (C) 2026  Markus Johnsson a.k.a. FerusX.Swe    All rights reserved.    This program is free software: you can redistribute it and/or modify    it under the terms of the GNU General Public License as published by    the Free Software Foundation, either version 3 of the License, or    (at your option) any later version.    This program is distributed in the hope that it will be useful,    but WITHOUT ANY WARRANTY; without even the implied warranty of    MERCHANTABILITY or FITNESS FOR A PARTICULAR PURPOSE.  See the    GNU General Public License for more details.    For the GNU General Public License, see <https://www.gnu.org/licenses/>."""import argparseimport sysimport jsonimport subprocessfrom dataclasses import dataclassfrom typing import List, Optional, Anyfrom datetime import datetime# =========================================================# GLOBALS# =========================================================# Header widths constantsPID_W = 7USER_W = 10CPU_W = 7MEM_W = 6RSS_W = 8THR_W = 5TIME_W = 8START_W = 10# Colors constantsGRAY = "\033[38;2;168;168;168m"WHITE = "\033[97m"CYAN = "\033[96m"RED = "\033[91m"YELLOW = '\033[38;2;200;180;60m'RESET = "\033[0m"# CPU Threshold constantDEFAULT_CPU_THRESHOLD = 1.0# =========================================================# Class: CustomArgumentParser# =========================================================class CustomArgumentParser(argparse.ArgumentParser):    """    Custom argument parser that overrides the default exit behavior.    Purpose:        Prevent argparse from terminating the program abruptly with sys.exit()        when encountering errors or help messages.    Behavior:        - Prints the error/help message to stderr (if present)        - Raises SystemExit manually instead of exiting internally    Why:        This allows better control over program flow and makes it possible        to handle argument parsing errors more cleanly, especially in tools        where you may want to intercept or customize exit behavior.    """    def exit(self, status=0, message=None):        """        Override of argparse.ArgumentParser.exit().        Instead of calling sys.exit() directly, this method:        - Prints the message (if any)        - Raises SystemExit with the given status        Args:            status (int): Exit status code            message (str, optional): Message to print before exiting        """        if message:            self._print_message(message, sys.stderr)        raise SystemExit(status)# =========================================================# Data class: ProcessInfo# =========================================================@dataclassclass ProcessInfo:    """    Data model representing a single process entry.    This class acts as a structured container for process information    collected from the system (via `ps`). Each instance corresponds    to one process and contains both raw and pre-processed attributes    used throughout the application.    Fields:        pid (int):            Process ID.        ppid (int):            Parent Process ID. Used for building the process tree.        user (str):            Username that owns the process.        cpu (float):            CPU usage percentage for this process.            Note: On BSD systems, this may exceed 100% on multicore systems.        mem (float):            Memory usage percentage.        rss_mb (float):            Resident Set Size in megabytes (physical memory usage).        started (str):            Full start time string as returned by `ps`            (e.g. "Thu Apr  2 17:06:03 2026", later formatted for display).        time (str):            Total CPU time consumed by the process            (raw format from `ps`, later formatted for display).        threads (int):            Number of threads associated with the process.        command (str):            Command or executable name of the process.    Role in the system:        - Produced by ProcessFetcher        - Filtered by ProcessFilter        - Sorted by ProcessSorter        - Consumed by Formatter and TreeFormatter    This class does NOT contain logic — it is strictly a data container.    """    pid: int    ppid: int    user: str    cpu: float    mem: float    rss_mb: float    started: str    time: str    threads: int    command: str# =========================================================# Function: format_time# =========================================================def format_time(raw_time: str) -> str:    """    Convert BSD ps TIME (MM:SS.xx or large minute values)    → HH:MM format    """    try:        if ":" not in raw_time:            return raw_time        # Example: "19803:31.55"        minutes_part = raw_time.split(":")[0]        total_minutes = int(minutes_part)        hours = total_minutes // 60        minutes = total_minutes % 60        return f"{hours:02}:{minutes:02}"    except Exception:        return raw_time# =========================================================# Function: format_started# =========================================================def format_started(started: str) -> str:    """    Format BSD start time into ps-like format:    - Today → HH:MM    - Older → Day + Date (Thu 2) OR Month + Date (Apr 2)    """    try:        dt = datetime.strptime(started, "%a %b %d %H:%M:%S %Y")        now = datetime.now()        # Same day → show time        if dt.date() == now.date():            return dt.strftime("%H:%M")        # Older → show day + date (NO month)        return dt.strftime("%a %d")        # OPTIONAL alternative:        # return dt.strftime("%b %d")    except Exception as ex:        return started# =========================================================# Function: print_summary# =========================================================def print_summary(count, use_color, mode="tree"):    """    Print a concise summary of the displayed output.    This function reports how many entries were rendered in the current    view (tree or table), providing quick feedback when working with    large or truncated outputs.    Args:        count (int): Number of entries displayed.        use_color (bool): Enable colored output if True.        mode (str): Output mode ("tree" or "table") to adjust wording.    """    if mode == "tree":        text = f"\n[Summary] Nodes displayed: {count}\n"    else:        text = f"\n[Summary] Processes displayed: {count}\n"    if use_color:        text = f"{CYAN}{text}{RESET}"    print(text)# =========================================================# Function: load_json_processes# =========================================================def load_json_processes(path):    """    Load process data from a JSON file and convert it into ProcessInfo objects.    Supports both flat JSON lists and tree-based JSON structures.    """    with open(path, "r") as f:        data = json.load(f)    processes = []    if not data:        return processes    is_tree = isinstance(data[0], dict) and "children" in data[0]    def walk(node, parent_pid=None):        if not node:            return        pid = node.get("pid")        ppid = node.get("ppid", parent_pid or 0)        processes.append(            ProcessInfo(                pid=pid,                ppid=ppid,                user=node.get("user", ""),                cpu=node.get("cpu", 0.0),                mem=node.get("mem", 0.0),                rss_mb=node.get("rss_mb", 0.0),                started=node.get("started", "N/A"),                time=node.get("time", "N/A"),                threads=node.get("threads", 0),                command=node.get("command", "")            )        )        # Only recurse if tree structure exists        if is_tree:            for child in node.get("children", []):                walk(child, pid)    #    if is_tree:        for root in data:            walk(root)    else:        # flat JSON → no recursion        for item in data:            walk(item)    return processes# =========================================================# Function: format_started_time# =========================================================def format_started_time(started_str):    try:        dt = datetime.strptime(started_str, "%a %b %d %H:%M:%S %Y")        now = datetime.now()        if dt.date() == now.date():            return dt.strftime("%H:%M")        else:            return dt.strftime("%a %d")    except Exception as ex:        return started_str# =========================================================# Class: ProcessFetcher# =========================================================class ProcessFetcher:    """    Responsible for retrieving process data from the system.    Uses the BSD `ps` command to collect raw process information    and converts each row into a structured ProcessInfo object.    NOTE: This is the ONLY component that interacts with the system.    """    # --------------------------------------------------------------------    # Method: fetch    # --------------------------------------------------------------------    @staticmethod    def fetch() -> List[ProcessInfo]:        """        Executes the `ps` command and parses its output into ProcessInfo objects.        Returns:            List[ProcessInfo]: List of all processes retrieved from the system        Notes:            - Relies on fixed column positions from the `ps` output            - Uses manual splitting to reconstruct multi-field values              such as start time and command            - Silently skips malformed lines        """        cmd = "ps -axo pid,ppid,user,%cpu,%mem,rss,lstart,time,nlwp,comm"        output = subprocess.check_output(cmd, shell=True, text=True)        # We skip the header line        lines = output.strip().split("\n")[1:]        processes = []        for line in lines:            try:                # Split into columns (lstart and command require reconstruction)                parts = line.split()                pid = int(parts[0])                ppid = int(parts[1])                user = parts[2]                cpu = float(parts[3])                mem = float(parts[4])                rss_kb = int(parts[5])                rss_mb = rss_kb / 1024                # lstart = 5 fields: "Thu Apr  2 17:06:03 2026"                started = " ".join(parts[6:11])                time = parts[11]                threads = int(parts[12])                # command may contain spaces → join remaining parts                command = " ".join(parts[13:])                processes.append(                    ProcessInfo(                        pid=pid,                        ppid=ppid,                        user=user,                        cpu=cpu,                        mem=mem,                        rss_mb=rss_mb,                        started=started,                        time=time,                        threads=threads,                        command=command                    )                )            except Exception:                # Skip malformed or unexpected lines safely                continue        return processes# =========================================================# Class: ProcessFilter# =========================================================class ProcessFilter:    """    Responsible for filtering process data based on user-provided criteria.    Applies optional filters such as:    - User ownership    - Specific PID    - Command substring matching    This stage operates on already fetched data and does not modify    the original list structure beyond filtering.    """    # --------------------------------------------------------------------    # Method: apply    # --------------------------------------------------------------------    @staticmethod    def apply(processes: List[ProcessInfo], args) -> List[ProcessInfo]:        """        Filter a list of ProcessInfo objects according to CLI arguments.        Args:            processes (List[ProcessInfo]):                The full list of processes to filter.            args:                Parsed command-line arguments containing optional filters.        Returns:            List[ProcessInfo]: Filtered list of processes        Notes:            - Filters are applied sequentially (user → pid → command)            - Each filter reduces the current result set            - String matching for command is case-insensitive        """        result = processes        # User        if args.user:            result = [p for p in result if p.user == args.user]        # PID        if args.pid:            result = [p for p in result if p.pid == args.pid]        # Filter        if args.filter:            result = [p for p in result if args.filter.lower() in p.command.lower()]        # ---------------------------------------        # Hide kernel processes (Default)        # ---------------------------------------        if not args.all:            result = [                p for p in result                if p.pid != 0 and p.command not in ("kernel", "idle")            ]        return result# =========================================================# Class: ProcessSorter# =========================================================class ProcessSorter:    """    Responsible for ordering processes based on user-defined criteria.    Supports sorting by: (default → descending)    - CPU usage    - Memory usage    - Process ID    - Resident Set Size in megabytes (physical memory usage).    - Threads    - Command (default → ascending, in lower-case)    Sorting direction can be reversed using the -b, --bottom flag.    """    # --------------------------------------------------------------------    # Method: apply    # --------------------------------------------------------------------    @staticmethod    def apply(processes: List[ProcessInfo], args) -> List[ProcessInfo]:        """        Sort a list of ProcessInfo objects according to CLI arguments.        Args:            processes (List[ProcessInfo]):                The list of processes to sort.            args:                Parsed command-line arguments containing sorting preferences.        Returns:            List[ProcessInfo]: A sorted list of processes        Notes:            - Default sorting is by CPU (descending)            - -b, --bottom reverses the sort order (ascending)            - Sorting is stable and uses Python's built-in sorted()        """        # Map CLI sort options to corresponding process attributes        key_map = {            "cpu": lambda p: p.cpu,            "mem": lambda p: p.mem,            "pid": lambda p: p.pid,            "rss": lambda p: p.rss_mb,            "thr": lambda p: p.threads,            "cmd": lambda p: (p.command or "").lower()        }        # Select sorting function (default: CPU)        key_func = key_map.get(args.sort, key_map["cpu"])        # Sort commands in ascending order        if args.sort == "cmd":            reverse = False  # always ascending for command        else:            # Reverse determines descending vs ascending order            reverse = not args.bottom  # default: descending        return sorted(processes, key=key_func, reverse=reverse)# =========================================================# Class: ProcessTreeBuilder# =========================================================class ProcessTreeBuilder:    """    Responsible for constructing the hierarchical process tree.    Converts a flat list of ProcessInfo objects into:    - A list of root processes    - A mapping of parent PID → child processes    This structure is later consumed by the tree formatter    for recursive rendering.    """    # --------------------------------------------------------------------    # Method: build    # --------------------------------------------------------------------    @staticmethod    def build(processes):        """        Build parent-child relationships from a flat process list.        Args:            processes (List[ProcessInfo]):                List of processes retrieved from the system.        Returns:            Tuple[List[ProcessInfo], Dict[int, List[ProcessInfo]]]:                - roots: Top-level processes (no valid parent)                - children: Mapping of PID → list of child processes        Notes:            - Uses PID lookup for fast parent resolution            - Ensures all PIDs exist in the children map            - Handles orphaned processes (missing parent)        """        children = {}        lookup = {}        # Build PID → Process lookup for fast parent checks        for p in processes:            lookup[p.pid] = p            children.setdefault(p.pid, [])        # Build parent → children mapping        for p in processes:            children.setdefault(p.ppid, [])            children[p.ppid].append(p)        # Identify root processes (no valid parent)        roots = []        for p in processes:            if p.ppid == 0 or p.ppid == 1 or p.ppid not in lookup:                roots.append(p)        return roots, children# =========================================================# Class: ProcessFormatter# =========================================================class ProcessFormatter:    """    Responsible for formatting process data into a structured    tabular representation for terminal output.    This class converts a list of ProcessInfo objects into aligned    text rows with fixed-width columns, ensuring readability in    CLI environments.    Handles:    - Column layout and alignment    - Numeric formatting (CPU, memory, RSS, time)    - Optional ANSI color styling    Does NOT:    - Fetch, filter, or sort data    - Perform any tree-based rendering    This formatter is used for the standard table (non-tree) view.    """    # --------------------------------------------------------------------    # Method: format    # --------------------------------------------------------------------    @staticmethod    def format(processes: List[ProcessInfo], use_color: bool) -> List[str]:        lines = []        # Format column headers (width)        header = (            f"{'PID':<{PID_W}}"            f"{'USER':<{USER_W}}"            f"{'CPU%':<{CPU_W}}"            f"{'MEM%':<{MEM_W}}"            f"{'RSS':<{RSS_W}}"            f"{'THR':<{THR_W}}"            f"{'STARTED':<{START_W}}"            f"{'TIME':<{TIME_W}}"            f"{'COMMAND'}"        )        lines.append("")        lines.append(header)        lines.append("-" * len(header))        # List and format processes (width)        for p in processes:            # Pre-format values FIRST            pid_str = f"{p.pid:<{PID_W}}"            user_str = f"{p.user:<{USER_W}}"            cpu_str = f"{p.cpu:.1f}"            mem_str = f"{p.mem:.1f}"            rss_str = f"{p.rss_mb:.1f}M"            thr_str = f"{p.threads}"            started = format_started(p.started)            time_str = format_time(p.time)            cmd_str = p.command            # Apply padding BEFORE color            pid_str = f"{pid_str:<{PID_W}}"            user_str = f"{user_str:<{USER_W}}"            cpu_str = f"{cpu_str:<{CPU_W}}"            mem_str = f"{mem_str:<{MEM_W}}"            rss_str = f"{rss_str:<{RSS_W}}"            thr_str = f"{thr_str:<{THR_W}}"            start_str = f"{started:<{START_W}}"            time_str = f"{time_str:<{TIME_W}}"            # Apply colors AFTER padding            if use_color:                pid_str = f"{WHITE}{pid_str}{RESET}"                user_str = f"{YELLOW}{user_str}{RESET}"                # CPU special logic (override base gray)                if p.cpu >= 80:                    cpu_str = f"{RED}{cpu_str}{RESET}"                elif p.cpu >= 40:                    cpu_str = f"{YELLOW}{cpu_str}{RESET}"                else:                    cpu_str = f"{GRAY}{cpu_str}{RESET}"                mem_str = f"{WHITE}{mem_str}{RESET}"                rss_str = f"{WHITE}{rss_str}{RESET}"                thr_str = f"{WHITE}{thr_str}{RESET}"                start_str = f"{GRAY}{start_str}{RESET}"                time_str = f"{GRAY}{time_str}{RESET}"                cmd_str = f"{CYAN}{cmd_str}{RESET}"            # Final line (NO formatting here anymore!)            line = (                f"{pid_str}"                f"{user_str}"                f"{cpu_str}"                f"{mem_str}"                f"{rss_str}"                f"{thr_str}"                f"{start_str}"                f"{time_str}"                f"{cmd_str}"            )            lines.append(line)        return lines# =========================================================# Class: ProcessTreeFormatter# =========================================================class ProcessTreeFormatter:    """    Responsible for rendering processes in a hierarchical tree structure.    This formatter takes a filtered/sorted process list and builds a visual    tree representation using parent-child relationships.    Core responsibilities:    - Build process tree structure via ProcessTreeBuilder    - Compute subtree CPU usage (including descendants)    - Sort nodes based on selected criteria    - Prune irrelevant or low-value branches    - Render tree using ASCII/UTF-8 branch glyphs    - Apply optional color formatting    Features:    - Subtree CPU aggregation with caching    - CPU visibility modes (--cpu-all, --cpu-threshold)    - Depth limiting (--tree-depth)    - Intelligent branch pruning    - Stable and safe recursion (loop protection)    This class operates purely on in-memory data and does not    interact with the system or modify process state.    """    # --------------------------------------------------------------------    # Method: format    # --------------------------------------------------------------------    @staticmethod    def format(processes: List[ProcessInfo],  all_processes, args, use_color: bool):        """        Render the process tree as a list of formatted strings.        Args:            processes (List[ProcessInfo]):                Filtered process list (visible nodes).            all_processes:                Full process list used to build complete tree structure.            args:                Parsed CLI arguments controlling sorting, depth,                CPU visibility, and output behavior.            use_color (bool):                Enable or disable ANSI color formatting.        Returns:            List[str]: Rendered tree lines ready for printing.        Notes:            - Tree structure is built from all_processes to preserve hierarchy            - Only processes in `processes` are considered visible            - Rendering respects depth limits and pruning rules        """        visible_pids = {p.pid for p in processes}        roots, children = ProcessTreeBuilder.build(all_processes)        subtree_cache = {}        # --------------------------------------------------------------------        # Method: compute_subtree_cpu        # --------------------------------------------------------------------        def compute_subtree_cpu(node, visited=None):            """            Recursively compute total CPU usage for a node and all descendants.            Uses memoization (subtree_cache) to avoid redundant calculations.            """            if visited is None:                visited = set()            if node.pid in visited:                return 0  # break cycle safely            visited.add(node.pid)            if node.pid in subtree_cache:                return subtree_cache[node.pid]            total = node.cpu            for child in children.get(node.pid, []):                total += compute_subtree_cpu(child, visited.copy())            subtree_cache[node.pid] = total            return total        sort_key_outer = args.sort        reverse = not args.bottom        # --------------------------------------------------------------------        # Method: get_sort_value        # --------------------------------------------------------------------        def get_sort_value(p):            """            Determine sorting value based on selected key.            For CPU sorting, subtree CPU is used instead of per-process CPU.            """            if sort_key_outer == "cpu":                return compute_subtree_cpu(p)            elif sort_key_outer == "mem":                return p.mem            elif sort_key_outer == "pid":                return p.pid            return compute_subtree_cpu(p)        roots = sorted(roots, key=get_sort_value, reverse=reverse)        lines = []        printed = set()        # --------------------------------------------------------------------        # Method: is_boring        # --------------------------------------------------------------------        def is_boring(node):            """            Identify low-value system processes that should be hidden            unless they contribute meaningful data to the tree.            Helps reduce visual noise in large process trees.            """            return (                    node.user == "root"                    and node.cpu == 0.0                    and node.mem == 0.0                    and node.command not in ("Xorg", "sshd", "init", "login")            )        # --------------------------------------------------------------------        # Method: has_visible_descendant        # --------------------------------------------------------------------        def has_visible_descendant(node, visited=None):            """            Determine whether a node or any of its descendants            should be displayed in the tree.            Prevents rendering of empty or irrelevant branches.            """            if visited is None:                visited = set()            if node.pid in visited:                return False            visited.add(node.pid)            if node.pid in visible_pids and not is_boring(node):                return True            for child in children.get(node.pid, []):                if has_visible_descendant(child, visited):                    return True            return False        # --------------------------------------------------------------------        # Method: format_subtree_cpu        # --------------------------------------------------------------------        def format_subtree_cpu(value):            """Format CPU value for display."""            return f"{value:.1f}%"        # --------------------------------------------------------------------        # Method: render        # --------------------------------------------------------------------        def render(node, prefix="", is_last=True, visited=None, depth=1):            """            Recursively render a process node and its children.            Handles:            - Tree glyph construction            - Depth limiting            - CPU display logic            - Color formatting            - Recursion safety            """            if args.depth is not None and depth > args.depth:                return            if node.pid in printed:                return            printed.add(node.pid)            if visited is None:                visited = set()            # Prevent infinite recursion            if node.pid in visited:                return            visited.add(node.pid)            branch = "└─ " if is_last else "├─ "            line_prefix = prefix + (branch if prefix else "")            pid_str = str(node.pid)            cmd_str = node.command            if use_color:                pid_str = f"{GRAY}{pid_str}{RESET}"                cmd_str = f"{CYAN}{cmd_str}{RESET}"            user_str = node.user            if use_color:                user_str = f"{YELLOW}{user_str}{RESET}"            if node.pid in visible_pids:                cpu_total = compute_subtree_cpu(node)                # Determine CPU visibility mode                if args.cpu_all:                    show_cpu = True                elif args.cpu_threshold is not None:                    show_cpu = cpu_total >= args.cpu_threshold                else:                    show_cpu = (prefix == "") or cpu_total > DEFAULT_CPU_THRESHOLD                cpu_part = ""                if show_cpu:                    cpu_str = format_subtree_cpu(cpu_total)                    if use_color:                        if cpu_total >= 80:                            cpu_str = f"{RED}{cpu_str}{RESET}"                        elif cpu_total >= 40:                            cpu_str = f"{YELLOW}{cpu_str}{RESET}"                        else:                            cpu_str = f"{GRAY}{cpu_str}{RESET}"                    cpu_part = f" (CPU: {cpu_str})"                lines.append(f"{line_prefix}{pid_str} {user_str} {cmd_str}{cpu_part}")            new_prefix = prefix + ("   " if is_last else "│  ")            sort_key = args.sort            if sort_key == "cpu":                key_func = lambda x: -x.cpu            elif sort_key == "mem":                key_func = lambda x: -x.mem            else:                key_func = lambda x: x.pid            children_nodes = sorted(                children.get(node.pid, []),                key=get_sort_value,                reverse=reverse            )            # Filter children to avoid rendering irrelevant branches            filtered_children = [                c for c in children_nodes                if has_visible_descendant(c) and not is_boring(c)            ]            for idx, child in enumerate(filtered_children):                if child.pid == node.pid:                    continue                render(child, new_prefix, idx == len(filtered_children) - 1, visited, depth + 1)        for i, root in enumerate(roots):            if has_visible_descendant(root):                render(root, "", i == len(roots) - 1, None, 1)        if args.number:            return lines[:args.number]        return lines# =========================================================# Function: build_tree_json_view# =========================================================def build_tree_json_view(roots, children, visible_pids, args):    """    Build a filtered JSON representation of the process tree.    This function produces a structured tree similar to the visual tree output,    but limited to a subset of processes defined by `visible_pids`. It respects    user-provided constraints such as depth and integrates recursion protection    to avoid infinite loops caused by cyclic parent-child relationships.    Behavior:        - Only processes in `visible_pids` are included.        - Traversal is restricted to relevant roots.        - Depth limiting is applied via `args.depth`.        - Cycles are prevented using a visited set per traversal path.        - Output is a list of root-level dictionaries with nested children.    Args:        roots (List[ProcessInfo]): Root processes of the full process tree.        children (Dict[int, List[ProcessInfo]]): Mapping of parent PID → child processes.        visible_pids (Set[int]): Set of PIDs allowed in the output.        args (Namespace): Parsed CLI arguments (depth, number, etc.).    Returns:        List[Dict]: JSON-serializable tree structure.    """    subtree_cache = {}    # --------------------------------------------------------------------    # Method: compute_subtree_cpu    # --------------------------------------------------------------------    def compute_subtree_cpu(proc, visited=None):        if visited is None:            visited = set()        if proc.pid in visited:            return 0.0        if proc.pid in subtree_cache:            return subtree_cache[proc.pid]        visited.add(proc.pid)        total = proc.cpu        for child in children.get(proc.pid, []):            if child.pid == proc.pid:                continue            total += compute_subtree_cpu(child, visited)        subtree_cache[proc.pid] = total        return total    # --------------------------------------------------------------------    # Method: build_node    # --------------------------------------------------------------------    def build_node(proc, depth=1, visited=None):        if visited is None:            visited = set()        if proc.pid in visited:            return None  # break cycle        visited.add(proc.pid)        if args.depth is not None and depth > args.depth:            return None        if proc.pid not in visible_pids:            return None        cpu_total = compute_subtree_cpu(proc)        node_data = {            "pid": proc.pid,            "ppid": proc.ppid,            "user": proc.user,            "command": proc.command,            "cpu": proc.cpu,            "subtree_cpu": cpu_total,            "mem": proc.mem,            "threads": proc.threads,            "started": getattr(proc, "started", "N/A"),            "time": getattr(proc, "time", "N/A"),            "rss_mb": proc.rss_mb,            "children": []        }        for child in children.get(proc.pid, []):            child_node = build_node(child, depth + 1, visited.copy())            if child_node:                node_data["children"].append(child_node)        return node_data    result = []    limited_roots = [        r for r in roots if r.pid in visible_pids    ]    for root in limited_roots:        node = build_node(root, 1, set())        if node:            result.append(node)    return result# =========================================================# Function: build_tree_json# =========================================================def build_tree_json(roots, children, args):    """    Convert process tree into JSON-serializable structure.    """    subtree_cache = {}    printed = set()    # --------------------------------------------------------------------    # Method: compute_subtree_cpu    # --------------------------------------------------------------------    def compute_subtree_cpu(node, visited):        if node.pid in visited:            return 0        visited.add(node.pid)        if node.pid in subtree_cache:            return subtree_cache[node.pid]        total = node.cpu        for child in children.get(node.pid, []):            if child.pid == node.pid:                continue            total += compute_subtree_cpu(child, visited.copy())        subtree_cache[node.pid] = total        return total    # --------------------------------------------------------------------    # Method: build_node    # --------------------------------------------------------------------    def build_node(node, depth=1, visited=None):        if visited is None:            visited = set()        # GLOBAL[!] protection (like tree renderer)        if node.pid in printed:            return None        printed.add(node.pid)        # recursion protection        if node.pid in visited:            return None        visited.add(node.pid)        if args.depth is not None and depth > args.depth:            return None        cpu_total = compute_subtree_cpu(node, set())        node_data = {            "pid": node.pid,            "ppid": node.ppid,            "user": node.user,            "command": node.command,            "cpu": node.cpu,            "subtree_cpu": cpu_total,            "mem": node.mem,            "threads": node.threads,            "rss_mb": node.rss_mb,            "started": node.started,            "time": node.time,            "children": []        }        for child in children.get(node.pid, []):            if child.pid == node.pid:                continue  # safety guard            child_node = build_node(child, depth + 1, visited.copy())            if child_node:                node_data["children"].append(child_node)        return node_data    return [        node        for root in roots        if root        for node in [build_node(root, 1, set())]        if node is not None    ]# =========================================================# Class: ProcessPrinter# =========================================================class ProcessPrinter:    """    Responsible for outputting formatted lines to the terminal.    This is the final stage in the processing pipeline, taking already    formatted text and sending it to standard output.    """    # --------------------------------------------------------------------    # Method: print    # --------------------------------------------------------------------    @staticmethod    def print(lines: List[str]):        """        Print each line to standard output.        Args:            lines (List[str]):                Formatted lines produced by a formatter.        """        for line in lines:            print(line)# =========================================================# Main App# =========================================================class ProcVwApp:    """    Main application controller for procvw.    Manages the full processing pipeline:        Fetch → Filter → Sort → Format → Print    Responsibilities:        - Parse command-line arguments        - Coordinate data flow between components        - Select output mode (table or tree)    This class contains no heavy logic itself — it delegates all work    to specialized components.    """    # ---------------------------------------------------------------------    # __init__    # ---------------------------------------------------------------------    def __init__(self):        """        Initialize the application and parse CLI arguments.        """        self.args = self._parse_args()        # Validate flags        self._validate_args()    # ---------------------------------------------------------------------    # Method: _parse_args    # ---------------------------------------------------------------------    def _parse_args(self):        """        Define and parse command-line arguments.        Returns:            argparse.Namespace: Parsed CLI arguments        Supported options:            - Filtering: --user, --pid, --filter            - Sorting: --sort, --bottom            - Output: --number, --color, --json            - View modes: --tree, --table, --json-view            - Tree enhancements: --cpu-all, --cpu-threshold, --tree-depth            - File: --save, --load            - General: --all        """        parser = CustomArgumentParser(            prog="procvw",            description="BSD Process Viewer",            formatter_class=argparse.RawTextHelpFormatter        )        parser.add_argument(            "-u",            "--user"        )        parser.add_argument(            "-f",            "--filter"        )        parser.add_argument(            "-p",            "--pid",            type=int        )        parser.add_argument(            "-s",            "--sort",            choices=["cpu", "mem", "pid", "rss", "cmd", "thr"],            default="cpu"        )        parser.add_argument(            "-b",            "--bottom",            action="store_true"        )        parser.add_argument(            "-n",            "--number",            type=int,            default=20        )        parser.add_argument(            "--color",            action="store_true"        )        parser.add_argument(            "--tree",            action="store_true",            help="Display processes in tree view"        )        parser.add_argument(            "--cpu-all",            action="store_true",            help="Show subtree CPU usage for all nodes (tree mode)"        )        parser.add_argument(            "--cpu-threshold",            type=float,            help="Show subtree CPU only for nodes above threshold"        )        parser.add_argument(            "--tree-depth",            type=int,            help="Limit tree depth (1 = root only)"        )        parser.add_argument(            "--load",            metavar="FILE",            help="Load process tree from JSON file instead of live system"        )        parser.add_argument(            "--save",            metavar="FILE",            help="Save output to JSON file"        )        parser.add_argument(            "--json",            action="store_true",            help="Output process data in JSON format"        )        parser.add_argument(            "--json-view",            action="store_true",            help="Output JSON matching visible tree view"        )        parser.add_argument(            "--table",            action="store_true",            help="Display processes in table view"        )        parser.add_argument(            "--all",            action="store_true",            help="Include kernel/system processes"        )        return parser.parse_args()    # ---------------------------------------------------------------------    # Method: _validate_args    # ---------------------------------------------------------------------    def _validate_args(self):        """ Validate arguments """        if self.args.table and self.args.tree:            raise SystemExit("ERROR: Cannot use --table and --tree together")        if self.args.table:            if self.args.cpu_all or self.args.cpu_threshold or self.args.depth:                raise SystemExit("ERROR: CPU/depth flags only apply to tree mode")        if self.args.json_view and self.args.table:            raise SystemExit("ERROR: --json-view requires tree mode")    # ---------------------------------------------------------------------    # Method: run    # ---------------------------------------------------------------------    def run(self):        """        Execute the application pipeline.        Flow:            1. Fetch processes from system            2. Apply filters (user, pid, command)            3. Sort processes            4. Render output (tree or table)            5. Print results to terminal        Notes:            - Tree mode requires a full process list to preserve hierarchy            - Standard mode limits output to --number entries        """        if self.args.load:            processes = load_json_processes(self.args.load)        else:            processes = ProcessFetcher.fetch()        processes = ProcessFilter.apply(processes, self.args)        processes = ProcessSorter.apply(processes, self.args)        if self.args.save:            # Always build full tree for saving            if self.args.load:                all_processes = processes            else:                all_processes = ProcessFetcher.fetch()            roots, children = ProcessTreeBuilder.build(all_processes)            data = build_tree_json(roots, children, self.args)            with open(self.args.save, "w") as f:                json.dump(data, f, indent=2)        if self.args.load and not self.args.table:            self.args.tree = True        if self.args.tree:            if self.args.load:                all_processes = processes            else:                all_processes = ProcessFetcher.fetch()            roots, children = ProcessTreeBuilder.build(all_processes)            if self.args.json or self.args.json_view:                if self.args.json_view:                    limited = processes[:self.args.number] if self.args.number else processes                    visible_pids = {p.pid for p in limited}                    data = build_tree_json_view(                        roots,                        children,                        visible_pids,                        self.args                    )                else:                    data = build_tree_json(roots, children, self.args)                json_output = json.dumps(data, indent=2)                if self.args.json or self.args.json_view or not self.args.save:                    print(json_output)                # COUNT NODES                def count_nodes(nodes):                    total = 0                    for n in nodes:                        if not n:                            continue                        total += 1                        total += count_nodes(n.get("children", []))                    return total                node_count = count_nodes(data)                print_summary(node_count, self.args.color)                return            # NORMAL TREE OUTPUT (ONLY REACHED IF NOT JSON)            lines = ProcessTreeFormatter.format(                processes,                all_processes,                self.args,                self.args.color            )        else:            if self.args.number:                processes = processes[: self.args.number]            if self.args.json:                data = [                    {                        "pid": p.pid,                        "ppid": p.ppid,                        "user": p.user,                        "command": p.command,                        "cpu": p.cpu,                        "mem": p.mem,                        "rss_mb": p.rss_mb,                        "threads": p.threads,                        "started": p.started,                        "time": p.time                    }                    for p in processes                ]                json_output = json.dumps(data, indent=2)                if self.args.save:                    with open(self.args.save, "w") as f:                        f.write(json_output)                if self.args.json or not self.args.save:                    print(json_output)                return            lines = ProcessFormatter.format(processes, self.args.color)        # Print to standard output        ProcessPrinter.print(lines)        ## Print a summary line below the table/tree view telling        ## how many processes/nodes were displayed        if self.args.tree:            print_summary(len(lines), self.args.color)        else:            print_summary(len(processes), self.args.color, mode="table")# =========================================================# Entry# =========================================================if __name__ == "__main__":    app = ProcVwApp()    app.run()